module sr_latch (input SR_S, input R, output reg Q, output reg Qn);  
    always @ (SR_S or R) begin  
        if (SR_S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end else if (!SR_S && R) begin  
            Q = 0;  
            Qn = 1;  
        end else if (!SR_S && !R) begin  
            // Maintain previous state  
        end  
    end  
endmodule
